d test code (javascript) 
<script>
<!-- this is tested on mozilla firefox 47.0 -->
function modular_multiplicative_inverse() {
var a = Math.abs(document.form.e.value);
var n = Math.abs(document.form.mod.value);
var t = 0;
 var nt = 1;
 var r = n;
 var nr = a % n;

[제목] RSA 암호
if (n < 0){
 n = -n;
 }
 if (a < 0){
 a = n - (-a % n);
 }
 while (nr !== 0) {
 var quot= (r/nr) | 0;
 var tmp = nt; nt = t - quot*nt; t = tmp;
 tmp = nr; nr = r - quot*nr; r = tmp;
 }
 if (r > 1) { return -1; }
 if (t < 0) { t += n; }
alert("d value="+t);
return t;

[제목] 자바스크립트
// Declares a block-scoped variable named `y`, and implicitly sets it to
// `undefined`. The `let` keyword was introduced in ECMAScript 2015.
let y;
// More explicit version of the above.
let y2 = undefined;

[제목] 자바스크립트
// Declares a block-scoped, un-reassign-able variable named `z`, and sets it to
// `undefined`. The `const` keyword was also introduced in ECMAScript 2015, and
// must be explicitly assigned to.
const z = undefined;
// Declares a variable named `myNumber`, and assigns a number literal (the value
// `2`) to it.
let myNumber = 2;

[제목] 자바스크립트
// Reassigns `myNumber`, setting it to a string literal (the value `"foo"`).
// JavaScript is a dynamically-typed language, so this is legal.
myNumber = "foo";
